   renderCharacter(character, context) {
-    // existing character rendering code
-    context.drawImage(character.sprite, character.x, character.y);
+    const x = character.x;
+    const y = character.y;
+    const sprite = character.sprite;
+
+    // Draw 1px dark outline by drawing the sprite shifted in 8 directions with a dark tint
+    context.save();
+    context.globalCompositeOperation = 'destination-over';
+    context.filter = 'brightness(0)'; // black silhouette
+    for (let dx = -1; dx <= 1; dx++) {
+      for (let dy = -1; dy <= 1; dy++) {
+        if (dx === 0 && dy === 0) continue;
+        context.drawImage(sprite, x + dx, y + dy);
+      }
+    }
+    context.restore();
+
+    // Draw drop shadow beneath character (subtle, offset down-right)
+    context.save();
+    context.shadowColor = 'rgba(0,0,0,0.3)';
+    context.shadowBlur = 4;
+    context.shadowOffsetX = 2;
+    context.shadowOffsetY = 2;
+    context.drawImage(sprite, x, y);
+    context.restore();
+
+    // Draw character sprite normally on top
+    context.drawImage(sprite, x, y);
   }
+
+  // Z-sorting method to sort characters and furniture by their y position
+  static zSort(entities) {
+    return entities.sort((a, b) => (a.y + a.height) - (b.y + b.height));
+  }
 }

 export default CharacterRenderer;
